// HTML에서 최신 공지 추출
const items = $input.all();
const results = [];

for (const item of items) {
  const html = item.json.data || item.json.body || '';
  // 간단한 링크/제목 추출 (Cheerio 없이)
  const linkRegex = /<a[^>]+href="([^"]+)"[^>]*>([^<]+)<\/a>/gi;
  let match;
  let count = 0;
  while ((match = linkRegex.exec(html)) && count < 10) {
    const url = match[1];
    const title = match[2].trim();
    if (title.length > 10 && (title.includes('化粧') || title.includes('cosmetic') || title.includes('薬') || title.includes('通知'))) {
      results.push({
        json: {
          source: item.json.url?.includes('pmda') ? 'pmda' : 'mhlw',
          title,
          url: url.startsWith('http') ? url : `https://www.mhlw.go.jp${url}`,
          region: 'JP',
          gemini_tag: 'GEMINI_JP'
        }
      });
      count++;
    }
  }
}

return results.length ? results : [{ json: { skip: true, region: 'JP' } }];

